// inferred-not-tested:原生 Illustration + 各 shape 构造器
import Zdog from 'https://cdn.jsdelivr.net/npm/zdog@1/+esm';
const canvas = document.createElement('canvas'); canvas.width = 640; canvas.height = 400;
canvas.style.cssText = 'display:block;width:100%;height:400px'; document.getElementById('zdog').appendChild(canvas);
const illo = new Zdog.Illustration({ ...data.illustration, element: canvas });
for (const s of data.shapes) new Zdog[s.type]({ ...s.options, addTo: illo });
(function frame(){ illo.updateRenderGraph(); requestAnimationFrame(frame); })();

